  onTick?: (clientX: number, clientY: number) => void,
) {
  let frameId: number | null = null;
  let dx = 0;
  let dy = 0;
  let lastClientX = 0;
  let lastClientY = 0;

  const tick = () => {
    if (dx === 0 && dy === 0) {
      frameId = null;
