import { useCallback, useEffect, useRef } from 'react';
import { getGenerationDropData, getDragType } from '@/shared/lib/dnd/dragDrop';
import { inferDragKind } from '@/tools/video-editor/lib/drop-position';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type { UseAssetManagementResult } from '@/tools/video-editor/hooks/useAssetManagement';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';
import type { ClipMeta, TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';
import type { TrackKind } from '@/tools/video-editor/types';
import { getCompatibleTrackId } from '@/tools/video-editor/lib/coordinate-utils';

export interface UseExternalDropArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  scale: number;
  scaleWidth: number;
  selectedTrackId: string | null;
  applyTimelineEdit: UseTimelineDataResult['applyTimelineEdit'];
  patchRegistry: UseTimelineDataResult['patchRegistry'];
  registerAsset: UseTimelineDataResult['registerAsset'];
  uploadAsset: UseTimelineDataResult['uploadAsset'];
  invalidateAssetRegistry: UseTimelineDataResult['invalidateAssetRegistry'];
  resolveAssetUrl: (file: string) => Promise<string>;
  coordinator: DragCoordinator;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  uploadImageGeneration: UseAssetManagementResult['uploadImageGeneration'];
  handleAssetDrop: UseAssetManagementResult['handleAssetDrop'];
  handleAddTextAt?: (trackId: string, time: number) => void;
}

export interface UseExternalDropResult {
  onTimelineDragOver: (event: React.DragEvent<HTMLDivElement>) => void;
  onTimelineDragLeave: (event: React.DragEvent<HTMLDivElement>) => void;
  onTimelineDrop: (event: React.DragEvent<HTMLDivElement>) => void;
}

export function useExternalDrop({
  dataRef,
  selectedTrackId,
  applyTimelineEdit,
  patchRegistry,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
  coordinator,
  registerGenerationAsset,
  uploadImageGeneration,
  handleAssetDrop,
  handleAddTextAt,
}: UseExternalDropArgs): UseExternalDropResult {
  const externalDragFrameRef = useRef<number | null>(null);
  const latestExternalDragRef = useRef<{
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
  } | null>(null);
  const latestExternalPositionRef = useRef<ReturnType<DragCoordinator['update']> | null>(null);

  const clearExternalDragState = useCallback(() => {
    if (externalDragFrameRef.current !== null) {
      window.cancelAnimationFrame(externalDragFrameRef.current);
      externalDragFrameRef.current = null;
    }
    latestExternalDragRef.current = null;
    latestExternalPositionRef.current = null;
    coordinator.end();
  }, [coordinator]);

  useEffect(() => {
    return () => {
      clearExternalDragState();
    };
  }, [clearExternalDragState]);

  const onTimelineDragOver = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    const dragType = getDragType(event);
    const types = Array.from(event.dataTransfer.types);
    if (!types.includes('asset-key') && !types.includes('text-tool') && dragType !== 'file' && dragType !== 'generation') {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    event.currentTarget.dataset.dragOver = 'true';
    latestExternalDragRef.current = {
      clientX: event.clientX,
      clientY: event.clientY,
      sourceKind: inferDragKind(event),
    };

    if (externalDragFrameRef.current !== null) {
      return;
    }

    externalDragFrameRef.current = window.requestAnimationFrame(() => {
      externalDragFrameRef.current = null;
      const currentDrag = latestExternalDragRef.current;
      if (!currentDrag) {
        return;
      }

      latestExternalPositionRef.current = coordinator.update({
        clientX: currentDrag.clientX,
        clientY: currentDrag.clientY,
        sourceKind: currentDrag.sourceKind,
      });
    });
  }, [coordinator]);

  const onTimelineDragLeave = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    delete event.currentTarget.dataset.dragOver;
    clearExternalDragState();
  }, [clearExternalDragState]);

  const onTimelineDrop = useCallback(async (event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    delete event.currentTarget.dataset.dragOver;
    if (externalDragFrameRef.current !== null) {
      window.cancelAnimationFrame(externalDragFrameRef.current);
      externalDragFrameRef.current = null;
    }

    if (latestExternalDragRef.current) {
      latestExternalPositionRef.current = coordinator.update({
        clientX: latestExternalDragRef.current.clientX,
        clientY: latestExternalDragRef.current.clientY,
        sourceKind: latestExternalDragRef.current.sourceKind,
      });
    }

    const dropPosition = coordinator.lastPosition
      ?? latestExternalPositionRef.current
      ?? coordinator.update({
        clientX: event.clientX,
        clientY: event.clientY,
        sourceKind: inferDragKind(event),
      });

    latestExternalDragRef.current = null;
    latestExternalPositionRef.current = null;
    coordinator.end();

    // Handle text-tool drop
    const isTextTool = event.dataTransfer.types.includes('text-tool');
    if (isTextTool && handleAddTextAt && dataRef.current) {
      let targetTrackId = dropPosition.isNewTrack ? undefined : dropPosition.trackId;
      if (!targetTrackId) {
        // Create a new visual track
        const current = dataRef.current;
        const existingCount = current.tracks.filter((t) => t.kind === 'visual').length;
        targetTrackId = `V${existingCount + 1}`;
        current.tracks.push({ id: targetTrackId, kind: 'visual', label: `Visual ${existingCount + 1}` });
        current.rows.push({ id: targetTrackId, actions: [] });
      }
      handleAddTextAt(targetTrackId, dropPosition.time);
      return;
    }

    const files = Array.from(event.dataTransfer.files);
    if (files.length > 0 && dataRef.current) {
      const { time, trackId: dropTrackId } = dropPosition;

      const defaultClipDuration = 5;
      let timeOffset = 0;

      for (const file of files) {
        const ext = file.name.slice(file.name.lastIndexOf('.')).toLowerCase();
        const kind: TrackKind = ['.mp3', '.wav', '.aac', '.m4a'].includes(ext) ? 'audio' : 'visual';
        const isImageFile = file.type.startsWith('image/')
          || ['.png', '.jpg', '.jpeg', '.webp', '.gif', '.bmp', '.avif'].includes(ext);
        let compatibleTrackId = dropPosition.isNewTrack
          ? null
          : getCompatibleTrackId(dataRef.current.tracks, dropTrackId, kind, selectedTrackId);
        // Create a new track if none is compatible or if dropping in the "new track" zone
        if (!compatibleTrackId) {
          const existingCount = dataRef.current.tracks.filter((t) => t.kind === kind).length;
          compatibleTrackId = `${kind === 'audio' ? 'A' : 'V'}${existingCount + 1}`;
          dataRef.current.tracks.push({
            id: compatibleTrackId,
            kind,
            label: `${kind === 'audio' ? 'Audio' : 'Visual'} ${existingCount + 1}`,
          });
          dataRef.current.rows.push({ id: compatibleTrackId, actions: [] });
        }

        const clipTime = time + timeOffset;
        timeOffset += defaultClipDuration;

        const skeletonId = `uploading-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
        const skeletonMeta: ClipMeta = {
          asset: `uploading:${file.name}`,
          track: compatibleTrackId,
          clipType: kind === 'audio' ? 'media' : 'hold',
          hold: kind === 'audio' ? undefined : defaultClipDuration,
          from: kind === 'audio' ? 0 : undefined,
          to: kind === 'audio' ? defaultClipDuration : undefined,
        };
        const skeletonAction: TimelineAction = {
          id: skeletonId,
          start: clipTime,
          end: clipTime + defaultClipDuration,
          effectId: `effect-${skeletonId}`,
        };

        const nextRows = dataRef.current.rows.map((row) =>
          row.id === compatibleTrackId
            ? { ...row, actions: [...row.actions, skeletonAction] }
            : row,
        );
        applyTimelineEdit(nextRows, { [skeletonId]: skeletonMeta }, undefined, undefined, { save: false });

        void (async () => {
          try {
            if (isImageFile) {
              const generationData = await uploadImageGeneration(file);
              const current = dataRef.current!;
              const cleanRows = current.rows.map((row) => ({
                ...row,
                actions: row.actions.filter((action) => action.id !== skeletonId),
              }));
              applyTimelineEdit(cleanRows, undefined, [skeletonId]);
              const assetId = registerGenerationAsset(generationData);

import { useCallback, useEffect, useMemo, useRef } from 'react';
import type { MutableRefObject } from 'react';
import type {
  DropIndicatorHandle,
  DropIndicatorPosition,
} from '@/tools/video-editor/components/TimelineEditor/DropIndicator';
import {
  computeDropPosition,
  type DropPosition,
} from '@/tools/video-editor/lib/drop-position';
import type { GhostRect } from '@/tools/video-editor/lib/multi-drag-utils';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TrackKind } from '@/tools/video-editor/types';

export interface DragCoordinator {
  update(params: {
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
    clipDuration?: number;
    clipOffsetX?: number;
  }): DropPosition;
  /** Show ghost outlines for secondary clips (non-anchor) during multi-drag. */
  showSecondaryGhosts(ghosts: GhostRect[]): void;
  end(): void;
  lastPosition: DropPosition | null;
  editAreaRef: MutableRefObject<HTMLElement | null>;
}

interface UseDragCoordinatorArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  scale: number;
  scaleWidth: number;
  startLeft: number;
  rowHeight: number;
}

interface UseDragCoordinatorResult {
  coordinator: DragCoordinator;
  indicatorRef: MutableRefObject<DropIndicatorHandle | null>;
  editAreaRef: MutableRefObject<HTMLElement | null>;
}

const buildFallbackPosition = (rowHeight: number, sourceKind: TrackKind | null): DropPosition => ({
  time: 0,
  rowIndex: 0,
  trackId: undefined,
  trackKind: sourceKind,
  trackName: '',
  isNewTrack: false,
  isReject: false,
  newTrackKind: null,
  screenCoords: {
    rowTop: 0,
    rowLeft: 0,
    rowWidth: 0,
    rowHeight,
    clipLeft: 0,
    clipWidth: 0,
    ghostCenter: 0,
  },
});

const toIndicatorPosition = (position: DropPosition): DropIndicatorPosition => {
  const timeLabel = `${position.time.toFixed(1)}s`;
  return {
    rowTop: position.screenCoords.rowTop,
    rowHeight: position.screenCoords.rowHeight,
    rowLeft: position.screenCoords.rowLeft,
    rowWidth: position.screenCoords.rowWidth,
    lineLeft: position.screenCoords.ghostCenter,
    ghostLeft: position.screenCoords.clipLeft,
    ghostTop: position.screenCoords.rowTop + 2,
    ghostWidth: position.screenCoords.clipWidth,
    ghostHeight: Math.max(0, position.screenCoords.rowHeight - 4),
    ghostLabel: timeLabel,
    label: position.trackName ? `${position.trackName} · ${timeLabel}` : timeLabel,
    isNewTrack: position.isNewTrack,
    newTrackKind: position.newTrackKind,
    reject: position.isReject,
  };
};

export function useDragCoordinator({
  dataRef,
  scale,
  scaleWidth,
  startLeft,
  rowHeight,
}: UseDragCoordinatorArgs): UseDragCoordinatorResult {
  const indicatorRef = useRef<DropIndicatorHandle | null>(null);
  const editAreaRef = useRef<HTMLElement | null>(null);
  const lastPositionRef = useRef<DropPosition | null>(null);
  const pendingIndicatorRef = useRef<DropIndicatorPosition | null>(null);
  const frameRef = useRef<number | null>(null);

  const flushIndicator = useCallback(() => {
    frameRef.current = null;
    const pending = pendingIndicatorRef.current;
    if (!pending) {
      return;
    }

    indicatorRef.current?.show(pending);
  }, []);

  const end = useCallback(() => {
    if (frameRef.current !== null) {
      window.cancelAnimationFrame(frameRef.current);
      frameRef.current = null;
    }

    pendingIndicatorRef.current = null;
    lastPositionRef.current = null;
    indicatorRef.current?.hide();
  }, []);

  const update = useCallback((params: {
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
    clipDuration?: number;
    clipOffsetX?: number;
  }): DropPosition => {
    const wrapper = editAreaRef.current?.closest<HTMLDivElement>('.timeline-wrapper');
    if (!wrapper) {
      const fallback = lastPositionRef.current ?? buildFallbackPosition(rowHeight, params.sourceKind);
      lastPositionRef.current = fallback;
      return fallback;
    }

    const nextPosition = computeDropPosition({
      clientX: params.clientX,
      clientY: params.clientY,
      wrapper,
      dataRef,
      scale,
      scaleWidth,
      startLeft,
      rowHeight,
      sourceKind: params.sourceKind,
      clipDuration: params.clipDuration,
      clipOffsetX: params.clipOffsetX,
    });

    lastPositionRef.current = nextPosition;
    pendingIndicatorRef.current = toIndicatorPosition(nextPosition);

    if (frameRef.current === null) {
      frameRef.current = window.requestAnimationFrame(flushIndicator);
    }

    return nextPosition;
  }, [dataRef, flushIndicator, rowHeight, scale, scaleWidth, startLeft]);

  const showSecondaryGhosts = useCallback((ghosts: GhostRect[]) => {
    indicatorRef.current?.showSecondaryGhosts(ghosts);
  }, []);

  useEffect(() => {
    return () => {
      end();
    };
  }, [end]);

  const coordinator = useMemo<DragCoordinator>(() => ({
    update,
    showSecondaryGhosts,
    end,
    editAreaRef,
    get lastPosition() {
      return lastPositionRef.current;
    },
  }), [editAreaRef, end, showSecondaryGhosts, update]);

  return {
    coordinator,
    indicatorRef,
    editAreaRef,
  };
}

import { useEffect, useRef } from 'react';
import type { MutableRefObject, RefObject } from 'react';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type { SelectClipOptions } from '@/tools/video-editor/hooks/useMultiSelect';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';
import type { TrackKind } from '@/tools/video-editor/types';
import type { ClipMeta, ClipOrderMap, TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import {
  type ClipOffset,
  planMultiDragMoves,
  applyMultiDragMoves,
  computeSecondaryGhosts,
} from '@/tools/video-editor/lib/multi-drag-utils';
import { createAutoScroller } from '@/tools/video-editor/lib/auto-scroll';
import { snapDrag } from '@/tools/video-editor/lib/snap-edges';

const DRAG_THRESHOLD_PX = 4;
/** Snap threshold in pixels — converted to seconds based on current zoom. */
const SNAP_THRESHOLD_PX = 8;
/** Vertical pixel threshold before activating cross-track mode. */
const CROSS_TRACK_THRESHOLD_PX = 10;

export interface ActionDragState {
  rowId: string;
  initialStart: number;
  initialEnd: number;
  latestStart: number;
  latestEnd: number;
}

interface UseCrossTrackDragOptions {
  timelineWrapperRef: RefObject<HTMLDivElement | null>;
  dataRef: MutableRefObject<TimelineData | null>;
  moveClipToRow: (clipId: string, targetRowId: string, newStartTime?: number) => void;
  createTrackAndMoveClip: (clipId: string, kind: TrackKind, newStartTime?: number) => void;
  selectClip: (clipId: string, opts?: SelectClipOptions) => void;
  selectClips: (clipIds: Iterable<string>) => void;
  selectedClipIdsRef: MutableRefObject<Set<string>>;
  applyTimelineEdit: (
    nextRows: TimelineRow[],
    metaUpdates?: Record<string, Partial<ClipMeta>>,
    metaDeletes?: string[],
    clipOrderOverride?: ClipOrderMap,
    options?: { save?: boolean },
  ) => void;
  coordinator: DragCoordinator;
  rowHeight: number;
  scale: number;
  scaleWidth: number;
  startLeft: number;
}

export interface DragSession {
  pointerId: number;
  clipId: string;
  sourceRowId: string;
  sourceKind: TrackKind;
  draggedClipIds: string[];
  clipOffsets: ClipOffset[];
  ctrlKey: boolean;
  metaKey: boolean;
  wasSelectedOnPointerDown: boolean;
  startClientX: number;
  startClientY: number;
  pointerOffsetX: number;
  pointerOffsetY: number;
  latestStart: number;
  clipDuration: number;
  clipEl: HTMLElement;
  moveListener: (event: PointerEvent) => void;
  upListener: (event: PointerEvent) => void;
  cancelListener: (event: PointerEvent) => void;
  /** Floating clone shown during cross-track drag. */
  floatingGhostEl: HTMLElement | null;
  countBadgeEl: HTMLSpanElement | null;
  hasMoved: boolean;
}

export interface UseClipDragResult {
  dragSessionRef: MutableRefObject<DragSession | null>;
}

export const useClipDrag = ({
  timelineWrapperRef,
  dataRef,
  moveClipToRow,
  createTrackAndMoveClip,
  selectClip,
  selectClips,
  selectedClipIdsRef,
  applyTimelineEdit,
  coordinator,
  rowHeight: _rowHeight,
  scale,
  scaleWidth,
  startLeft: _startLeft,
}: UseCrossTrackDragOptions): UseClipDragResult => {
  const dragSessionRef = useRef<DragSession | null>(null);
  const actionDragStateRef = useRef<ActionDragState | null>(null);
  const crossTrackActiveRef = useRef(false);
  const autoScrollerRef = useRef<ReturnType<typeof createAutoScroller> | null>(null);

  // Keep volatile values in refs so the effect doesn't re-run mid-drag
  // when zoom/scale changes.
  const coordinatorRef = useRef(coordinator);
  coordinatorRef.current = coordinator;
  const scaleRef = useRef(scale);
  scaleRef.current = scale;
  const scaleWidthRef = useRef(scaleWidth);
  scaleWidthRef.current = scaleWidth;
  const moveClipToRowRef = useRef(moveClipToRow);
  moveClipToRowRef.current = moveClipToRow;
  const createTrackAndMoveClipRef = useRef(createTrackAndMoveClip);
  createTrackAndMoveClipRef.current = createTrackAndMoveClip;
